import React from 'react';
import './UserAddress.css';

const UserAddress = () => {
    const [show, setShow] = React.useState(false);
    const [savedAddresses, setSavedAddresses] = React.useState([
        {
            id: 1,
            AddressLine1: 'AddressLine1',
            AddressLine2: 'AddressLine2',
            AddressLine3: 'AddressLine3',
        },
        {
            id: 2,
            AddressLine1: 'AddressLine5',
            AddressLine2: 'AddressLine6',
            AddressLine3: 'AddressLine7',
        },
        {
            id: 3,
            AddressLine1: 'AddressLine8',
            AddressLine2: 'AddressLine9',
            AddressLine3: 'AddressLine10',
        }
    ]);
    const [formData, setFormData] = React.useState({
        AddressLine1: '',
        AddressLine2: '',
        AddressLine3: '',
    });
    const [editId, setEditId] = React.useState(null);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            [name]: value,
        });
    };

    const handleSaveAddress = () => {
        if (editId) {
            // Update existing address
            const updatedAddresses = savedAddresses.map(address =>
                address.id === editId ? { ...address, ...formData } : address
            );
            setSavedAddresses(updatedAddresses);
            setEditId(null);
        } else {
            // Add new address
            const newAddress = {
                id: savedAddresses.length + 1,
                ...formData,
            };
            setSavedAddresses([...savedAddresses, newAddress]);
        }
        setFormData({
            AddressLine1: '',
            AddressLine2: '',
            AddressLine3: '',
        });
        setShow(false);
    };

    const handleDeleteAddress = (id) => {
        const updatedAddresses = savedAddresses.filter(address => address.id !== id);
        setSavedAddresses(updatedAddresses);
    };

    const handleEditAddress = (address) => {
        setFormData(address);
        setEditId(address.id);
        setShow(true);
    };

    return (
        <div className='useraddress'>
            {!show && <h1 className='mainhead1'>Your Address</h1>}
            {!show && (
                <div className='addressin'>
                    {savedAddresses.map((item) => (
                        <div className='address' key={item.id}>
                            <span>{item.AddressLine1}</span>,
                            <span>{item.AddressLine2}</span>,
                            <span>{item.AddressLine3}</span>
                            <div className='delbtn' onClick={() => handleDeleteAddress(item.id)}>
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                                </svg>
                            </div>
                            <div className='editbtn' onClick={() => handleEditAddress(item)}>
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 011.13-1.897l8.932-8.931zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10" />
                                </svg>
                            </div>
                        </div>
                    ))}
                </div>
            )}
            {!show && (
                <div className='addnewbtn' onClick={() => setShow(true)}>
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                    </svg>
                </div>
            )}
            {show && (
                <div className='addnew'>
                    <h1 className='mainhead1'>{editId ? 'Edit Address' : 'Add New Address'}</h1>
                    <div className='form'>
                        <div className='form-group'>
                            <label htmlFor='addressline1'>Address Line 1</label>
                            <input
                                type="text"
                                name="AddressLine1"
                                value={formData.AddressLine1}
                                onChange={handleInputChange}
                            />
                        </div>
                        <div className='form-group'>
                            <label htmlFor='addressline2'>Address Line 2</label>
                            <input
                                type="text"
                                name="AddressLine2"
                                value={formData.AddressLine2}
                                onChange={handleInputChange}
                            />
                        </div>
                        <div className='form-group'>
                            <label htmlFor='addressline3'>Address Line 3</label>
                            <input
                                type="text"
                                name="AddressLine3"
                                value={formData.AddressLine3}
                                onChange={handleInputChange}
                            />
                        </div>
                    </div>
                    <button className='mainbutton1' onClick={handleSaveAddress}>
                        {editId ? 'Update' : 'Save'}
                    </button>
                    <button className='mainbutton1' onClick={() => setShow(false)}>
                        Cancel
                    </button>
                </div>
            )}
        </div>
    );
};

export default UserAddress;
